mapper.select:
SELECT c.chunk_id AS chunkId, c.doc_id AS docId, c.kb_id AS kbId, d.title AS docTitle, c.content AS content, c.page_num AS pageNum, c.embedding_json AS embeddingJson, 0 AS score FROM ai_knowledge_chunk c INNER JOIN ai_knowledge_document d ON c.doc_id = d.doc_id AND c.doc_version = d.doc_version AND d.del_flag = '0' AND d.status = '0' AND d.index_status = 'DONE' INNER JOIN ai_knowledge_base b ON c.kb_id = b.kb_id AND b.del_flag = '0' AND b.status = '0' WHERE c.embedding_json IS NOT NULL
AND c.chunk_id < #{lastChunkId}
ORDER BY c.chunk_id DESC LIMIT #{limit}
